# Allowlist of permitted table names to prevent SQL injection
ALLOWED_TABLES = frozenset({
    'users',
    'orders',
    'products',
    'categories',
    'inventory',
})

# Allowlist of permitted columns per table
ALLOWED_COLUMNS = {
    'users': frozenset({'id', 'username', 'email', 'created_at', 'status'}),
    'orders': frozenset({'id', 'user_id', 'total', 'status', 'created_at'}),
    'products': frozenset({'id', 'name', 'description', 'price', 'category_id', 'created_at'}),
    'categories': frozenset({'id', 'name', 'description'}),
    'inventory': frozenset({'id', 'product_id', 'quantity', 'updated_at'}),
}

# Maximum number of rows to return
MAX_LIMIT = 1000
DEFAULT_LIMIT = 100


def validate_table_name(table_name):
    """Validate table name against strict allowlist."""
    if not table_name or not isinstance(table_name, str):
        raise ValueError("Table name is required and must be a string")

    table_name = table_name.strip().lower()

    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not in the allowed tables list")

    return table_name


def validate_columns(columns, table_name):
    """Validate column names against allowlist for the given table."""
    if not columns:
        return None

    if not isinstance(columns, list):
        raise ValueError("Columns must be a list of strings")

    allowed = ALLOWED_COLUMNS.get(table_name, frozenset())
    validated = []

    for col in columns:
        if not isinstance(col, str):
            raise ValueError("Each column name must be a string")

        col = col.strip().lower()

        # Additional regex check - only allow alphanumeric and underscores
        if not re.match(r'^[a-z][a-z0-9_]{0,62}$', col):
            raise ValueError(f"Invalid column name format: '{col}'")

        if col not in allowed:
            raise ValueError(f"Column '{col}' is not allowed for table '{table_name}'")

        validated.append(col)

    if not validated:
        raise ValueError("At least one valid column must be specified")

    return validated


def validate_limit(limit):
    """Validate and sanitize the limit parameter."""
    if limit is None:
        return DEFAULT_LIMIT

    try:
        limit = int(limit)
    except (TypeError, ValueError):
        raise ValueError("Limit must be a valid integer")

    if limit < 1:
        raise ValueError("Limit must be at least 1")

    return min(limit, MAX_LIMIT)


def validate_offset(offset):
    """Validate and sanitize the offset parameter."""
    if offset is None:
        return 0

    try:
        offset = int(offset)
    except (TypeError, ValueError):
        raise ValueError("Offset must be a valid integer")

    if offset < 0:
        raise ValueError("Offset must be non-negative")

    return offset


def validate_filters(filters, table_name):
    """
    Validate filter conditions against allowed columns.
    Returns a list of (column, operator, value) tuples.
    """
    if not filters:
        return []

    if not isinstance(filters, dict):
        raise ValueError("Filters must be a dictionary")

    allowed = ALLOWED_COLUMNS.get(table_name, frozenset())
    allowed_operators = frozenset({'eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'like', 'in'})
    validated_filters = []

    for key, condition in filters.items():
        if not isinstance(key, str):
            raise ValueError("Filter keys must be strings")

        col = key.strip().lower()

        if not re.match(r'^[a-z][a-z0-9_]{0,62}$', col):
            raise ValueError(f"Invalid filter column name: '{col}'")

        if col not in allowed:
            raise ValueError(f"Filter column '{col}' is not allowed for table '{table_name}'")

        if isinstance(condition, dict):
            for op, value in condition.items():
                op = op.strip().lower()
                if op not in allowed_operators:
                    raise ValueError(f"Operator '{op}' is not allowed. Use: {allowed_operators}")
                validated_filters.append((col, op, value))
        else:
            # Simple equality
            validated_filters.append((col, 'eq', condition))

    return validated_filters


def build_query(table_name, columns, filters, limit, offset, order_by=None):
    """
    Build a parameterized SQL query.
    Uses psycopg2's sql module for safe identifier quoting.
    """
    from psycopg2 import sql

    # Build SELECT clause
    if columns:
        select_cols = sql.SQL(', ').join(
            [sql.Identifier(col) for col in columns]
        )
    else:
        # Select all allowed columns for the table
        allowed = sorted(ALLOWED_COLUMNS.get(table_name, []))
        if allowed:
            select_cols = sql.SQL(', ').join(
                [sql.Identifier(col) for col in allowed]
            )
        else:
            select_cols = sql.SQL('*')

    query = sql.SQL("SELECT {columns} FROM {table}").format(
        columns=select_cols,
        table=sql.Identifier(table_name)
    )

    params = []

    # Build WHERE clause with parameterized values
    if filters:
        operator_map = {
            'eq': '=',
            'neq': '!=',
            'gt': '>',
            'gte': '>=',
            'lt': '<',
            'lte': '<=',
        }

        where_clauses = []
        for col, op, value in filters:
            if op == 'like':
                if not isinstance(value, str):
                    raise ValueError(f"LIKE filter value must be a string for column '{col}'")
                # Escape special LIKE characters in the value
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                clause = sql.SQL("{col} LIKE {val}").format(
                    col=sql.Identifier(col),
                    val=sql.Placeholder()
                )
                params.append(f'%{escaped_value}%')
                where_clauses.append(clause)
            elif op == 'in':
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError(f"IN filter value must be a non-empty list for column '{col}'")
                if len(value) > 100:
                    raise ValueError(f"IN filter for column '{col}' exceeds maximum of 100 values")
                clause = sql.SQL("{col} = ANY({val})").format(
                    col=sql.Identifier(col),
                    val=sql.Placeholder()
                )
                params.append(value)
                where_clauses.append(clause)
            elif op in operator_map:
                clause = sql.SQL("{col} " + operator_map[op] + " {val}").format(
                    col=sql.Identifier(col),
                    val=sql.Placeholder()
                )
                params.append(value)
                where_clauses.append(clause)

        if where_clauses:
            query = sql.SQL("{query} WHERE {where}").format(
                query=query,
                where=sql.SQL(' AND ').join(where_clauses)
            )

    # ORDER BY clause
    if order_by:
        col_name = order_by.get('column', '').strip().lower() if isinstance(order_by, dict) else None
        direction = order_by.get('direction', 'asc').strip().lower() if isinstance(order_by, dict) else 'asc'

        allowed = ALLOWED_COLUMNS.get(table_name, frozenset())
        if col_name and col_name in allowed and direction in ('asc', 'desc'):
            dir_sql = sql.SQL("ASC") if direction == 'asc' else sql.SQL("DESC")
            query = sql.SQL("{query} ORDER BY {col} {dir}").format(
                query=query,
                col=sql.Identifier(col_name),
                dir=dir_sql
            )

    # LIMIT and OFFSET with parameterized values
    query = sql.SQL("{query} LIMIT {limit} OFFSET {offset}").format(
        query=query,
        limit=sql.Placeholder(),
        offset=sql.Placeholder()
    )
    params.extend([limit, offset])

    return query, params


def build_response(status_code, body, headers=None):
    """Build a standardized API Gateway response."""
    response = {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Content-Type-Options': 'nosniff',
            'Cache-Control': 'no-store',
            'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        },
        'body': json.dumps(body, default=str),
    }

    if headers:
        response['headers'].update(headers)

    return response


